void solve(int CASE)
{
	int n, k; cin >> n >> k;
	Trie t;
	var s = vector<string>(n + 1);
	fa(i, 1, n) {
		cin >> s[i];
		t.insert(s[i]);
	}

	// 遍历整个字典树，当遍历过程中，截止的字符串个数刚好为 k 时，输出答案
	string pre;
	var dfs = [&](var dfs, TrieNode* now, int cnt)->void {
		if (cnt > k)return;

		if (cnt + t.ends[now->id] == k) {
			cout << pre << endl;
			exit(0);
		}

		for (char c : {'0', '1'}) {
			if (now->children.count(c)) {
				pre.pb(c);
				dfs(dfs, now->children[c], cnt + t.ends[now->id]);
				pre.pop_back();
			}
		}
		};
	dfs(dfs, t.root, 0);

	cout << -1 << endl;
	return;
}
